import React, { useState, useEffect } from 'react';
import axios from 'axios';
import EditTask from '../EditTask/EditTask';
import DeleteTask from '../DeleteTask/DeleteTask';

function TodoList(){
    const [tasks, setTasks] = useState([]);
    const [openModal, setOpenModal] = useState(false);
    
    useEffect(()=>{
        axios.get('http://localhost:8001/todos')        
        .then((res)=>{
            console.log('successfully data fetched: ', res);
            setTasks(res.data.tasks);
        })
        .catch((err)=>{
            console.log(err);
        })
    }, [])
    function editTask(){

    }
    function deleteTask(){

    }
    return(
        <div className="container-fluid" id="to-do-list">
            <table>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Description</th>
                        <th>Priority</th>
                        <th>Status</th>
                        <th>Target Date</th>
                        <th>UserID</th>
                    </tr>
                </thead>
                <tbody>
                    {
                        tasks.map((task)=>{
                            return(<tr>
                                <td>{task.id}</td>
                                <td>{task.description}</td>
                                <td>{task.priority}</td>
                                <td>{task.status}</td>
                                <td>{task.target_date}</td>
                                <td>{task.user_id}</td>
                                <td>        
                                    <button 
                                        className='openModalBtn' 
                                        onClick={()=>{setOpenModal(true);}}
                                    >
                                        Edit
                                    </button>
                                    {openModal && <EditTask id={task.id} closeModal={setOpenModal}/>}
                                </td>
                                <td>        
                                    <button 
                                        className='openModalBtn' 
                                        onClick={()=>{setOpenModal(true);}}
                                    >
                                        Delete
                                    </button>
                                    {openModal && <DeleteTask id={task.id} closeModal={setOpenModal}/>}
                                </td>
                            </tr>

                            )
                        })
                    }
                </tbody>
            </table>
        </div>
    )
}

export default TodoList;
